  /// @solidity memory-safe-assembly\\n                assembly {\\n                    let returndata_size := mload(returndata)\\n                    revert(add(32, returndata), returndata_size)\\n                }\\n            } else {\\n                revert(errorMessage);\\n            }\\n        }\\n    }\\n}\\n\"},\"node_modules/@scroll-tech/contracts/libraries/IScrollMessenger.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\n\\npragma solidity ^0.8.24;\\n\\ninterface IScrollMessenger {\\n    /**********\\n     * Events *\\n     **********/\\n\\n    /// @notice Emitted when a cross domain message is sent.\\n    /// @param sender The address of the sender who initiates the message.\\n    /// @param target The address of target contract to call.\\n    /// @param value The amount of value passed to the target contract.\\n    /// @param messageNonce The nonce of the message.\\n    /// @param gasLimit The optional gas limit passed to L1 or L2.\\n    /// @param message The calldata passed to the target contract.\\n    event SentMessage(\\n        address indexed sender,\\n        address indexed target,\\n        uint256 value,\\n        uint256 messageNonce,\\n        uint256 gasLimit,\\n        bytes message\\n    );\\n\\n    /// @notice Emitted when a cross domain message is relayed successfully.\\n    /// @param messageHash The hash of the message.\\n    event RelayedMessage(bytes32 indexed messageHash);\\n\\n    /// @notice Emitted when a cross domain message is failed to relay.\\n    /// @param messageHash The hash of the message.\\n    event FailedRelayedMessage(bytes32 indexed messageHash);\\n\\n    /**********\\n     * Errors *\\n     **********/\\n\\n    /// @dev Thrown when the given address is `address(0)`.\\n    error ErrorZeroAddress();\\n\\n    /*************************\\n     * Public View Functions *\\n     *************************/\\n\\n    /// @notice Return the sender of a cross domain message.\\n    function xDomainMessageSender() external view returns (address);\\n\\n    /*****************************\\n     * Public Mutating Functions *\\n     *****************************/\\n\\n    /// @notice Send cross chain message from L1 to L2 or L2 to L1.\\n    /// @param target The address of account who receive the message.\\n    /// @param value The amount of ether passed when call target contract.\\n    /// @param message The content of the message.\\n    /// @param gasLimit Gas limit required to complete the message relay on corresponding chain.\\n    function sendMessage(\\n        address target,\\n        uint256 value,\\n        bytes calldata message,\\n        uint256 gasLimit\\n    ) external payable;\\n\\n    /// @notice Send cross chain message from L1 to L2 or L2 to L1.\\n    /// @param target The address of account who receive the message.\\n    /// @param value The amount of ether passed when call target contract.\\n    /// @param message The content of the message.\\n    /// @param gasLimit Gas limit required to complete the message relay on corresponding chain.\\n    /// @param refundAddress The address of account who will receive the refunded fee.\\n    function sendMessage(\\n        address target,\\n        uint256 value,\\n        bytes calldata message,\\n        uint256 gasLimit,\\n        address refundAddress\\n    ) external payable;\\n}\\n\"},\"src/v0.8/l2ep/CrossDomainForwarder.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\nimport {CrossDomainOwnable} from \\\"./CrossDomainOwnable.sol\\\";\\nimport {IForwarder} from \\\"./interfaces/IForwarder.sol\\\";\\n\\n/**\\n * @title CrossDomainForwarder - L1 xDomain account representation\\n * @notice L2 Contract which receives messages from a specific L1 address and transparently forwards them to the\\n * destination.\\n * @dev Any other L2 contract which uses this contract's address as a privileged position,\\n *   can consider that position to be held by the `l1Owner`\\n */\\nabstract contract CrossDomainForwarder is IForwarder, CrossDomainOwnable {}\\n\"},\"src/v0.8/l2ep/CrossDomainOwnable.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\nimport {ConfirmedOwner} from \\\"../shared/access/ConfirmedOwner.sol\\\";\\nimport {ICrossDomainOwnable} from \\\"./interfaces/ICrossDomainOwnable.sol\\\";\\n\\n/**\\n * @title The CrossDomainOwnable contract\\n * @notice A contract with helpers for cross-domain contract ownership.\\n */\\ncontract CrossDomainOwnable is ICrossDomainOwnable, ConfirmedOwner {\\n  address internal s_l1Owner;\\n  address internal s_l1PendingOwner;\\n\\n  constructor(\\n    address newl1Owner\\n  ) ConfirmedOwner(msg.sender) {\\n    _setL1Owner(newl1Owner);\\n  }\\n\\n  /**\\n   * @notice transfer ownership of this account to a new L1 owner\\n   * @param to new L1 owner that will be allowed to call the forward fn\\n   */\\n  function transferL1Ownership(\\n    address to\\n  ) public virtual override onlyL1Owner {\\n    _transferL1Ownership(to);\\n  }\\n\\n  /**\\n   * @notice accept ownership of this account to a new L1 owner\\n   */\\n  function acceptL1Ownership() public virtual override onlyProposedL1Owner {\\n    _setL1Owner(s_l1PendingOwner);\\n  }\\n\\n  /**\\n   * @notice Get the current owner\\n   */\\n  function l1Owner() public view override returns (address) {\\n    return s_l1Owner;\\n  }\\n\\n  /**\\n   * @notice validate, transfer ownership, and emit relevant events\\n   */\\n  function _transferL1Ownership(\\n    address to\\n  ) internal {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(to != msg.sender, \\\"Cannot transfer to self\\\");\\n\\n    s_l1PendingOwner = to;\\n\\n    emit L1OwnershipTransferRequested(s_l1Owner, to);\\n  }\\n\\n  /**\\n   * @notice set ownership, emit relevant events. Used in acceptOwnership()\\n   */\\n  function _setL1Owner(\\n    address to\\n  ) internal {\\n    address oldOwner = s_l1Owner;\\n    s_l1Owner = to;\\n    s_l1PendingOwner = address(0);\\n\\n    emit L1OwnershipTransferred(oldOwner, to);\\n  }\\n\\n  /**\\n   * @notice Reverts if called by anyone other than the L1 owner.\\n   */\\n  modifier onlyL1Owner() virtual {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(msg.sender == s_l1Owner, \\\"Only callable by L1 owner\\\");\\n    _;\\n  }\\n\\n  /**\\n   * @notice Reverts if called by anyone other than the L1 owner.\\n   */\\n  modifier onlyProposedL1Owner() virtual {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(msg.sender == s_l1PendingOwner, \\\"Only callable by proposed L1 owner\\\");\\n    _;\\n  }\\n}\\n\"},\"src/v0.8/l2ep/interfaces/ICrossDomainOwnable.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\n/// @title A contract with helpers for cross-domain contract ownership\\ninterface ICrossDomainOwnable {\\n  event L1OwnershipTransferRequested(address indexed from, address indexed to);\\n\\n  event L1OwnershipTransferred(address indexed from, address indexed to);\\n\\n  function l1Owner() external returns (address);\\n\\n  function transferL1Ownership(\\n    address recipient\\n  ) external;\\n\\n  function acceptL1Ownership() external;\\n}\\n\"},\"src/v0.8/l2ep/interfaces/IDelegateForwarder.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\n/// @title Forwards a delegatecall to a target, under some conditions\\ninterface IDelegateForwarder {\\n  /// @notice forward delegatecalls the `target` with `data`\\n  /// @param target contract address to be delegatecalled\\n  /// @param data to send to target contract\\n  function forwardDelegate(address target, bytes memory data) external;\\n}\\n\"},\"src/v0.8/l2ep/interfaces/IForwarder.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\n/// @title Forwards a call to a target, under some conditions\\ninterface IForwarder {\\n  /// @notice forward calls the `target` with `data`\\n  /// @param target contract address to be called\\n  /// @param data to send to target contract\\n  function forward(address target, bytes memory data) external;\\n}\\n\"},\"src/v0.8/l2ep/scroll/ScrollCrossDomainGovernor.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity 0.8.24;\\n\\nimport {ITypeAndVersion} from \\\"../../shared/interfaces/ITypeAndVersion.sol\\\";\\nimport {IDelegateForwarder} from \\\"../interfaces/IDelegateForwarder.sol\\\";\\n// solhint-disable-next-line no-unused-import\\nimport {IForwarder} from \\\"../interfaces/IForwarder.sol\\\";\\n\\nimport {CrossDomainForwarder} from \\\"../CrossDomainForwarder.sol\\\";\\nimport {CrossDomainOwnable} from \\\"../CrossDomainOwnable.sol\\\";\\n\\nimport {Address} from \\\"@openzeppelin/contracts@4.7.3/utils/Address.sol\\\";\\nimport {IScrollMessenger} from \\\"@scroll-tech/contracts/libraries/IScrollMessenger.sol\\\";\\n\\n/// @title ScrollCrossDomainGovernor - L1 xDomain account representation (with delegatecall support) for Scroll\\n/// @notice L2 Contract which receives messages from a specific L1 address and transparently forwards them to the\\n/// destination.\\n/// @dev Any other L2 contract which uses this contract's address as a privileged position,\\n/// can be considered to be simultaneously owned by the `l1Owner` and L2 `owner`\\ncontract ScrollCrossDomainGovernor is IDelegateForwarder, ITypeAndVersion, CrossDomainForwarder {\\n  string public constant override typeAndVersion = \\\"ScrollCrossDomainGovernor 1.0.0\\\";\\n\\n  address internal immutable i_scrollCrossDomainMessenger;\\n\\n  /// @param crossDomainMessengerAddr the xDomain bridge messenger (Scroll bridge L2) contract address\\n  /// @param l1OwnerAddr the L1 owner address that will be allowed to call the forward fn\\n  constructor(IScrollMessenger crossDomainMessengerAddr, address l1OwnerAddr) CrossDomainOwnable(l1OwnerAddr) {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(address(crossDomainMessengerAddr) != address(0), \\\"Invalid xDomain Messenger address\\\");\\n    i_scrollCrossDomainMessenger = address(crossDomainMessengerAddr);\\n  }\\n\\n  /// @inheritdoc IForwarder\\n  /// @dev forwarded only if L2 Messenger calls with `msg.sender` being the L1 owner address, or called by the L2 owner\\n  function forward(address target, bytes memory data) external override onlyLocalOrCrossDomainOwner {\\n    Address.functionCall(target, data, \\\"Governor call reverted\\\");\\n  }\\n\\n  /// @inheritdoc IDelegateForwarder\\n  /// @dev forwarded only if L2 Messenger calls with `msg.sender` being the L1 owner address, or called by the L2 owner\\n  function forwardDelegate(address target, bytes memory data) external override onlyLocalOrCrossDomainOwner {\\n    Address.functionDelegateCall(target, data, \\\"Governor delegatecall reverted\\\");\\n  }\\n\\n  /// @notice The address of the Scroll Cross Domain Messenger contract\\n  function crossDomainMessenger() external view returns (address) {\\n    return address(i_scrollCrossDomainMessenger);\\n  }\\n\\n  /// @notice The call MUST come from the L1 owner (via cross-chain message.) Reverts otherwise.\\n  modifier onlyL1Owner() override {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(msg.sender == i_scrollCrossDomainMessenger, \\\"Sender is not the L2 messenger\\\");\\n    // solhint-disable-next-line gas-custom-errors\\n    require(\\n      IScrollMessenger(i_scrollCrossDomainMessenger).xDomainMessageSender() == l1Owner(),\\n      \\\"xDomain sender is not the L1 owner\\\"\\n    );\\n    _;\\n  }\\n\\n  /// @notice The call MUST come from either the L1 owner (via cross-chain message) or the L2 owner. Reverts otherwise.\\n  modifier onlyLocalOrCrossDomainOwner() {\\n    // 1. The delegatecall MUST come from either the L1 owner (via cross-chain message) or the L2 owner\\n    // solhint-disable-next-line gas-custom-errors\\n    require(\\n      msg.sender == i_scrollCrossDomainMessenger || msg.sender == owner(), \\\"Sender is not the L2 messenger or owner\\\"\\n    );\\n    // 2. The L2 Messenger's caller MUST be the L1 Owner\\n    if (msg.sender == i_scrollCrossDomainMessenger) {\\n      // solhint-disable-next-line gas-custom-errors\\n      require(\\n        IScrollMessenger(i_scrollCrossDomainMessenger).xDomainMessageSender() == l1Owner(),\\n        \\\"xDomain sender is not the L1 owner\\\"\\n      );\\n    }\\n    _;\\n  }\\n\\n  /// @notice The call MUST come from the proposed L1 owner (via cross-chain message.) Reverts otherwise.\\n  modifier onlyProposedL1Owner() override {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(msg.sender == i_scrollCrossDomainMessenger, \\\"Sender is not the L2 messenger\\\");\\n    // solhint-disable-next-line gas-custom-errors\\n    require(\\n      IScrollMessenger(i_scrollCrossDomainMessenger).xDomainMessageSender() == s_l1PendingOwner,\\n      \\\"Must be proposed L1 owner\\\"\\n    );\\n    _;\\n  }\\n}\\n\"},\"src/v0.8/shared/access/ConfirmedOwner.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\nimport {ConfirmedOwnerWithProposal} from \\\"./ConfirmedOwnerWithProposal.sol\\\";\\n\\n/// @title The ConfirmedOwner contract\\n/// @notice A contract with helpers for basic contract ownership.\\ncontract ConfirmedOwner is ConfirmedOwnerWithProposal {\\n  constructor(\\n    address newOwner\\n  ) ConfirmedOwnerWithProposal(newOwner, address(0)) {}\\n}\\n\"},\"src/v0.8/shared/access/ConfirmedOwnerWithProposal.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\nimport {IOwnable} from \\\"../interfaces/IOwnable.sol\\\";\\n\\n/// @title The ConfirmedOwner contract\\n/// @notice A contract with helpers for basic contract ownership.\\ncontract ConfirmedOwnerWithProposal is IOwnable {\\n  address private s_owner;\\n  address private s_pendingOwner;\\n\\n  event OwnershipTransferRequested(address indexed from, address indexed to);\\n  event OwnershipTransferred(address indexed from, address indexed to);\\n\\n  constructor(address newOwner, address pendingOwner) {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(newOwner != address(0), \\\"Cannot set owner to zero\\\");\\n\\n    s_owner = newOwner;\\n    if (pendingOwner != address(0)) {\\n      _transferOwnership(pendingOwner);\\n    }\\n  }\\n\\n  /// @notice Allows an owner to begin transferring ownership to a new address.\\n  function transferOwnership(\\n    address to\\n  ) public override onlyOwner {\\n    _transferOwnership(to);\\n  }\\n\\n  /// @notice Allows an ownership transfer to be completed by the recipient.\\n  function acceptOwnership() external override {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(msg.sender == s_pendingOwner, \\\"Must be proposed owner\\\");\\n\\n    address oldOwner = s_owner;\\n    s_owner = msg.sender;\\n    s_pendingOwner = address(0);\\n\\n    emit OwnershipTransferred(oldOwner, msg.sender);\\n  }\\n\\n  /// @notice Get the current owner\\n  function owner() public view override returns (address) {\\n    return s_owner;\\n  }\\n\\n  /// @notice validate, transfer ownership, and emit relevant events\\n  function _transferOwnership(\\n    address to\\n  ) private {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(to != msg.sender, \\\"Cannot transfer to self\\\");\\n\\n    s_pendingOwner = to;\\n\\n    emit OwnershipTransferRequested(s_owner, to);\\n  }\\n\\n  /// @notice validate access\\n  function _validateOwnership() internal view {\\n    // solhint-disable-next-line gas-custom-errors\\n    require(msg.sender == s_owner, \\\"Only callable by owner\\\");\\n  }\\n\\n  /// @notice Reverts if called by anyone other than the contract owner.\\n  modifier onlyOwner() {\\n    _validateOwnership();\\n    _;\\n  }\\n}\\n\"},\"src/v0.8/shared/interfaces/IOwnable.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\ninterface IOwnable {\\n  function owner() external returns (address);\\n\\n  function transferOwnership(\\n    address recipient\\n  ) external;\\n\\n  function acceptOwnership() external;\\n}\\n\"},\"src/v0.8/shared/interfaces/ITypeAndVersion.sol\":{\"content\":\"// SPDX-License-Identifier: MIT\\npragma solidity ^0.8.0;\\n\\ninterface ITypeAndVersion {\\n  function typeAndVersion() external pure returns (string memory);\\n}\\n\"}}}"
